class Solution:
    def maxXorSubsequences(self, nums):
        # Independent reduced-row-echelon basis keyed by highest set bit, top bit down.
        basis = {}
        for x in nums:
            cur = x
            for bit in sorted(basis.keys(), reverse=True):
                if (cur >> bit) & 1:
                    cur ^= basis[bit]
            if cur:
                hb = cur.bit_length() - 1
                basis[hb] = cur
        res = 0
        for bit in sorted(basis.keys(), reverse=True):
            if not ((res >> bit) & 1):
                res ^= basis[bit]
        return res

