class Solution:
    def maxXorSubsequences(self, nums):
        basis = []
        for x in nums:
            cur = x
            for b in basis:
                cur = min(cur, cur ^ b)
            if cur:
                basis.append(cur)
                basis.sort(reverse=True)
        res = 0
        for b in basis:
            if (res ^ b) > res:
                res ^= b
        return res

