var maxXorSubsequences = function(nums) {
    const basis = [];
    for (const x of nums) {
        let cur = x;
        for (const b of basis) {
            if ((cur ^ b) < cur) cur ^= b;
        }
        if (cur) {
            basis.push(cur);
            basis.sort((a, b) => b - a);
        }
    }
    let res = 0;
    for (const b of basis) {
        if ((res ^ b) > res) res ^= b;
    }
    return res;
};
